    14→function formatNumber(value: string): string {
    15→  const num = parseFloat(value);
    16→  if (isNaN(num)) return '0';
    17→  return new Intl.NumberFormat('en-US', {
    18→    minimumFractionDigits: 0,
    19→    maximumFractionDigits: 0,
    20→  }).format(num);
    21→}
