    23→function getGrandTotal(data: BalanceSummaryDto, currency: SalaryCurrency): string {
    24→  switch (currency) {
    25→    case 'USD': return data.grandTotalUSD;
    26→    case 'EUR': return data.grandTotalEUR;
    27→    case 'RUB': return data.grandTotalRUB;
    28→  }
    29→}
