   116→function CurrencyDropdown({
   117→  value,
   118→  onChange,
   119→}: {
   120→  value: SalaryCurrency;
   121→  onChange: (c: SalaryCurrency) => void;
   122→}) {
   123→  const [open, setOpen] = useState(false);
   124→  const ref = useRef<HTMLDivElement>(null);
   125→
   126→  useEffect(() => {
   127→    function onPointerDown(e: PointerEvent) {
   128→      if (ref.current && !ref.current.contains(e.target as Node)) setOpen(false);
   129→    }
   130→    document.addEventListener('pointerdown', onPointerDown);
   131→    return () => document.removeEventListener('pointerdown', onPointerDown);
   132→  }, []);
   133→
   134→  return (
   135→    <div ref={ref} className={`salary-currency${open ? ' salary-currency--open' : ''}`}>
   136→      <button
   137→        type="button"
   138→        className="salary-currency__trigger"
   139→        onClick={() => setOpen((v) => !v)}
   140→      >
   141→        <span>{value}</span>
   142→        <svg className={`salary-currency__chevron${open ? ' salary-currency__chevron--open' : ''}`} width="16" height="16" viewBox="0 0 16 16" fill="none">
   143→          <path d="M4 6l4 4 4-4" stroke="currentColor" strokeLinecap="round" strokeLinejoin="round" />
   144→        </svg>
   145→      </button>
   146→      {open && (
   147→        <ul className="salary-currency__dropdown">
   148→          {SALARY_CURRENCIES.map((c) => (
   149→            <li key={c}>
   150→              <button
   151→                type="button"
   152→                className={`salary-currency__option${c === value ? ' salary-currency__option--active' : ''}`}
   153→                onClick={() => { onChange(c); setOpen(false); }}
   154→              >
   155→                {c}
   156→              </button>
   157→            </li>
   158→          ))}
   159→        </ul>
   160→      )}
   161→    </div>
   162→  );
   163→}
