   173→  const currency = useCurrencyStore((s) => s.currency);
   174→  const setCurrency = useCurrencyStore((s) => s.setCurrency);
   175→
   176→  useEffect(() => {
   177→    fetchBalanceSummary().then(setBalance).catch(() => {});
   178→  }, []);
   179→
   180→  const displayName = user?.displayName ?? user?.email?.split('@')[0] ?? '';
   181→  const displayEmail = user?.email ?? '';
   182→
   183→  const totalSymbol = CURRENCY_SYMBOLS[currency];
   184→  const totalNumber = balance ? formatNumber(getGrandTotal(balance, currency)) : '—';
   185→
   186→  return (
   187→    <aside className="sidebar">
   188→      <div className="sidebar__top">
   189→        {/* Logo */}
   190→        <div className="sidebar__logo">
   191→          <Image src="/icons/cryptonly-icon.svg" alt="" className="sidebar__logo-icon" width={26} height={26} />
   192→          <span className="sidebar__logo-text">CRYPTONLY</span>
   193→        </div>
   194→
   195→        <div className="sidebar__divider" />
   196→
   197→        {/* Total salary card */}
   198→        <div className="sidebar__salary-card">
   199→          <div className="sidebar__salary-card-bg" aria-hidden="true" />
   200→          <div className="sidebar__salary-header">
