   202→            <CurrencyDropdown value={currency} onChange={setCurrency} />
   203→          </div>
   204→          <p className="sidebar__salary-amount">
   205→            <span className="sidebar__salary-symbol">{totalSymbol}</span>
   206→            <span>{totalNumber}</span>
   207→          </p>
   208→        </div>
   209→
   210→        {/* Navigation */}
   211→        <nav className="sidebar__nav">
   212→          <p className="sidebar__nav-label">{t('sidebar.menu').toUpperCase()}</p>
   213→          <ul className="sidebar__nav-list">
   214→            {NAV_ITEMS.map((item) => {
   215→              const active = pathname === item.href || pathname.startsWith(item.href + '/');
   216→              return (
   217→                <li key={item.key}>
   218→                  <Link
   219→                    href={item.href}
   220→                    className={`sidebar__nav-item${active ? ' sidebar__nav-item--active' : ''}`}
   221→                  >
   222→                    <span className="sidebar__nav-icon">{item.icon(active)}</span>
   223→                    <span>{t(`nav.${item.key}` as const)}</span>
   224→                  </Link>
   225→                </li>
   226→              );
   227→            })}
   228→          </ul>
   229→        </nav>
   230→      </div>
   231→
   232→      {/* Bottom section */}
   233→      <div className="sidebar__bottom">
   234→        <LanguageSwitcher className="sidebar__lang-switcher" />
   235→
   236→        <div className="sidebar__user-card">
   237→          <div className="sidebar__user-info">
   238→            <p className="sidebar__user-name">{displayName}</p>
   239→            <p className="sidebar__user-email">{displayEmail}</p>
   240→          </div>
   241→          <div className="sidebar__user-divider" />
   242→          <div className="sidebar__user-links">
   243→            <Link href="/settings" className="sidebar__user-link">
   244→              <IconSettings />
   245→              <span>{t('sidebar.settings')}</span>
   246→            </Link>
   247→            <button type="button" className="sidebar__user-link" onClick={logoutAndClear}>
   248→              <IconExit />
   249→              <span>{t('sidebar.exit')}</span>
   250→            </button>
