     3→import { useEffect, useState } from 'react';
     4→import { useRouter } from 'next/navigation';
     5→import { useSessionStore } from '@/entities/session';
     6→import { AppLayout } from '@/widgets/app-layout';
     7→
     8→export default function DashboardLayout({
     9→  children,
    10→}: {
    11→  children: React.ReactNode;
    12→}) {
    13→  const router = useRouter();
    14→  const accessToken = useSessionStore((s) => s.accessToken);
    15→  const user = useSessionStore((s) => s.user);
    16→
    17→  // `ready` must start as false so the server-rendered HTML (which has no
    18→  // localStorage access) and the first client render both return null,
    19→  // preventing a hydration mismatch.
    20→  const [ready, setReady] = useState(false);
    21→
    22→  const authenticated =
    23→    !!accessToken && !!user && !!user.emailVerified && user.tenantId !== null;
    24→
    25→  useEffect(() => {
    26→    if (!authenticated) {
    27→      router.replace('/');
    28→      return;
    29→    }
    30→    // eslint-disable-next-line react-hooks/set-state-in-effect
    31→    setReady(true);
    32→  }, [authenticated, router]);
    33→
    34→  if (!ready) return null;
    35→
    36→  return <AppLayout>{children}</AppLayout>;
    37→}
